197	  // Caller invariant: the CPU must already be out of reset.
198	  void apply_resume_from_qemu(const std::string& path)
199	  {
200	    hybrid::SystemCDmiBus<PLATFORM::dmi_addr_width, PLATFORM::dmi_data_width>
201	      bus{platform.dmi, platform.clk.period()};
202	    hybrid_input_state_ = hybrid::load_state(path);
203	    hybrid::ResumeDriver driver(bus);
204	    driver.resume(*hybrid_input_state_);
205	  }
