207	  // Enables the vsim->QEMU handoff drain. After this is set, run() watches
208	  // committed PCs and on retire of a `csrw 0x7C0, *` exit-trigger drains
209	  // architectural state to `state_out_path` and returns kExitHandoffToQemu.
210	  void enable_hybrid_handoff(const std::string& elf_path,
211	                             const std::string& state_out_path)
212	  {
213	    auto elf = LIEF::ELF::Parser::parse(elf_path);
214	    if (!elf)
215	      throw std::runtime_error(
216	        "enable_hybrid_handoff: failed to parse " + elf_path);
217	
218	    hybrid::CsrTrigger trigger;
219	    for (const auto& seg: elf->segments()) {
220	      if (seg.type() != LIEF::ELF::SEGMENT_TYPES::PT_LOAD) continue;
221	      if ((static_cast<unsigned>(seg.flags()) & 1u) == 0u) continue;  // PF_X
222	      const auto content = seg.content();
223	      const std::span<const uint8_t> bytes{content.data(), content.size()};
224	      trigger.scan_buffer(bytes, seg.virtual_address());
225	    }
226	
227	    hybrid_dmi_bus_ = std::make_unique<
228	      hybrid::SystemCDmiBus<PLATFORM::dmi_addr_width,
229	                            PLATFORM::dmi_data_width>>(platform.dmi,
230	                                                       platform.clk.period());
231	    hybrid_handoff_.emplace(std::move(trigger), *hybrid_dmi_bus_);
232	    if (hybrid_input_state_)
233	      hybrid_handoff_->set_passthrough_input(&*hybrid_input_state_);
234	    hybrid_state_path_ = state_out_path;
235	  }
