275	  void load_image(const std::string& path, MEM_TYPE type)
276	  {
277	    switch (type) {
278	    case MEM_TYPE::ILM:
279	      if constexpr (requires { cpu.set_ilm({}); }) {
280	        read_binary_file(path, [this](const auto& data) { cpu.set_ilm(data); });
281	      } else {
282	        throw std::runtime_error(
283	          "CPU does not support ILM - cannot load ILM ROM image");
284	      }
285	      break;
286	
287	    case MEM_TYPE::DLM:
288	      if constexpr (requires { cpu.set_dlm({}); }) {
289	        read_binary_file(path, [this](const auto& data) { cpu.set_dlm(data); });
290	      } else {
291	        throw std::runtime_error(
292	          "CPU does not support DLM - cannot load DLM ROM image");
293	      }
294	      break;
295	
296	    case MEM_TYPE::RAM:
297	      read_binary_file(path, [this](const auto& data) {
298	        if (data.size() > platform.main_memory.data.size())
299	          throw std::runtime_error("RAM image size exceeds main memory size");
300	        std::copy(data.begin(), data.end(), platform.main_memory.data.begin());
301	      });
302	      break;
303	
304	    default:
305	      throw std::runtime_error("Unknown memory type");
306	    }
307	  }
