309	  void reset()
310	  {
311	    static constexpr int core_num = CPU::NDS_NHART;
312	    static constexpr int reset_val = (1 << core_num) - 1;
313	
314	    platform.resetn.write(0);
315	    auto saved = context_config;
316	    context_config = {};
317	    this->run(1);
318	    context_config = saved;
319	
320	    for (size_t i = 0; i < platform.reset_vector.size(); ++i)
321	      spdlog::info("hart {} reset vector: {:#x}", i,
322	                   (uint64_t) platform.reset_vector[i].read());
323	
324	    platform.resetn.write(reset_val);
325	
326	    if (context_config.continue_from)
327	      restore_context(context_config.dir);
328	  }
