330	  int run(const uint64_t max_cycles = std::numeric_limits<uint64_t>::max())
331	  {
332	    auto sa = memzeroed<struct sigaction>();
333	    sa.sa_handler = sigint_handler;
334	    sigemptyset(&sa.sa_mask);
335	
336	    auto oact = memzeroed<struct sigaction>();
337	    if (sigaction(SIGINT, &sa, &oact) == -1)
338	      perror("sigaction");
339	
340	    const auto restore_sigint = std::experimental::scope_exit{[&] {
341	      if (sigaction(SIGINT, &oact, nullptr) == -1)
342	        perror("sigaction");
343	    }};
344	
345	    // wait for debugger connections
346	    while (dtm_debug && !dtm.is_connected()) {
347	      dtm.try_accept_socket();
348	      if (ctrlc != 0) {
349	        return 130;
350	      }
351	      sleep(1);
352	    }
353	
354	    [[maybe_unused]]
355	    bool ctx_resuming = context_config.continue_from;
356	    [[maybe_unused]]
357	    bool ctx_triggered = false;
358	
359	    for (auto n = uint64_t{0}; n < max_cycles; ++n) {
360	
361	      if (ctx_resuming) [[unlikely]] {
362	        // Pull up PLIC interrupt signal at the first cycle of the resume
363	        platform.int_trigger.write(1);
364	        ctx_resuming = false;
365	        ctx_triggered = true;
366	      }
367	
368	      sc_core::sc_start(platform.clk.period());
369	
370	      trace_.on_cycle(cpu);
371	
372	      if (hybrid_handoff_) [[unlikely]] {
373	        if (auto code = check_hybrid_handoff(); code) return *code;
374	      }
375	
376	      if (trace_.pipeview_wants_exit()) {
377	        spdlog::info("Pipeline viewer requested exit (Kanata loop window complete)");
378	        return 0;
379	      }
380	
381	      if (context_config.save_on_wfi && platform.wfi_signal.read() == true)
382	        [[unlikely]]
383	      {
384	        context_config.save(platform, cpu);
385	        spdlog::info("User save context");
386	        return 0;
387	      }
388	
389	      if (ctrlc != 0) {
390	        ctrlc = 0;
391	        spdlog::info("Ctrl+C PC: {:x}", get_current_pc());
392	        trace_.log_committed_pcs(cpu);
393	        return 130;
394	      }
395	
396	      if (ctx_triggered) [[unlikely]] {
397	        // Pull down the interrupt signal after 1 cycle
398	        platform.int_trigger.write(0);
399	        ctx_triggered = false;
400	      }
401	
402	      if (platform.sim_control.exits >= 0) {
403	        spdlog::info("sim_control: got exit {}, stopping",
404	                     platform.sim_control.exits);
405	        spdlog::info("Exit PC: {:x}", get_current_pc());
406	        trace_.log_committed_pcs(cpu);
407	        return platform.sim_control.exits;
408	      }
409	
410	      if (this->cpu.contextp()->gotFinish())
411	        return 0;
412	
413	      spdlog::trace("PC: {:x}", get_current_pc());
414	    }
415	    return 0;
416	  }
