426	  auto check_hybrid_handoff() -> std::optional<int>
427	  {
428	    if constexpr (!requires { cpu.get_committed_pc(); }) {
429	      return std::nullopt;
430	    } else {
431	      const auto committed = cpu.get_committed_pc();
432	      if (committed.empty()) return std::nullopt;
433	      for (const auto pc: committed[0]) {
434	        auto state = hybrid_handoff_->on_retire(
435	          pc, [&](uint8_t r) -> uint64_t {
436	            if constexpr (requires { cpu.get_gpr(r); }) {
437	              return cpu.get_gpr(r);
438	            }
439	            return 0;
440	          });
441	        if (state) {
442	          spdlog::info("hybrid handoff: drained at pc=0x{:x}, writing {}",
443	                       pc, hybrid_state_path_);
444	          std::ofstream f(hybrid_state_path_, std::ios::binary);
445	          f.write(reinterpret_cast<const char*>(&*state), sizeof(*state));
446	          return hybrid::kExitHandoffToQemu;
447	        }
448	      }
449	      return std::nullopt;
450	    }
451	  }
