152	// Fetches a qXfer:features:read annex in full, looping while the stub
153	// answers with the 'm' (more) marker. QEMU's RISC-V CSR XML is ~6 KB and
154	// PacketSize is typically 1000 bytes, so several iterations are normal.
155	inline auto fetch_feature_xml(gdbstub::Session& sess, const std::string& annex)
156	  -> std::string
157	{
158	  std::string accum;
159	  std::size_t offset = 0;
160	  // Use a chunk size below the QEMU default PacketSize=1000. Asking for
161	  // 0x100 keeps each frame well under the wire limit even after the 'm'
162	  // marker and packet framing overhead.
163	  constexpr std::size_t kChunk = 0x100;
164	  while (true) {
165	    char buf[64];
166	    std::snprintf(buf, sizeof(buf), ":%zx,%zx", offset, kChunk);
167	    auto body = sess.send_command("qXfer:features:read:" + annex + buf);
168	    if (body.empty())
169	      throw std::runtime_error("qXfer empty reply for " + annex);
170	    const char marker = body.front();
171	    if (marker != 'l' && marker != 'm')
172	      throw std::runtime_error("qXfer non-l/m reply for " + annex + ": "
173	                               + std::string{marker});
174	    accum.append(body.substr(1));
175	    if (marker == 'l') return accum;
176	    offset += body.size() - 1;
177	  }
178	}
179	
180	// Walks target.xml and every <xi:include> annex, returning the merged
181	// register-name -> packet-number map.
182	inline auto discover_reg_map(gdbstub::Session& sess) -> gdbstub::RegMap
183	{
184	  gdbstub::RegMap map;
185	  const auto target_xml = fetch_feature_xml(sess, "target.xml");
186	  unsigned next = 0;
187	  for (const auto& annex : gdbstub::parse_target_xml(target_xml)) {
188	    const auto annex_xml = fetch_feature_xml(sess, annex);
189	    gdbstub::parse_feature_xml(annex_xml, map, next);
190	  }
191	  return map;
192	}
