255	// Restores x1..x31, PC, FPR (if HYBRID_FLAG_FP), M-mode CSRs, PMP, and
256	// vector data regs (if HYBRID_FLAG_V) into the QEMU vCPU via the gdbstub
257	// at `port`, then continues. Caller is responsible for waitpid().
258	inline void restore_state_via_gdbstub(uint16_t port,
259	                                      const hybrid_state_v1& state,
260	                                      pid_t child_pid = -1)
261	{
262	  spdlog::info("hybrid handback: connecting to gdbstub on tcp::{}", port);
263	  const int fd = detail::connect_loopback(port, std::chrono::seconds(5),
264	                                          child_pid);
265	  spdlog::info("hybrid handback: connected, discovering register map");
266	  gdbstub::Session sess{fd};
267	
268	  const auto reg_map = detail::discover_reg_map(sess);
269	  spdlog::info("hybrid handback: {} registers advertised, restoring state",
270	               reg_map.name_to_num.size());
271	
272	  // RV64 core: x0..x31 = 0..31, pc = 32. Hard-coded because the core
273	  // feature is always first.
274	  for (unsigned i = 1; i < 32; ++i) {
275	    auto reply = sess.send_command(gdbstub::encode_p_body(i, state.gpr[i]));
276	    if (reply != "OK")
277	      throw std::runtime_error(
278	        "gdbstub: P packet for x" + std::to_string(i) + " replied " + reply);
279	  }
280	  auto reply = sess.send_command(gdbstub::encode_p_body(32, state.pc));
281	  if (reply != "OK")
282	    throw std::runtime_error("gdbstub: P32 (pc) replied " + reply);
283	
284	  if ((state.flags & HYBRID_FLAG_FP) != 0u)
285	    for (std::size_t i = 0; i < detail::kFprNames.size(); ++i)
286	      detail::try_write_named(sess, reg_map, detail::kFprNames[i],
287	                              state.fpr[i]);
288	
289	  for (const auto& slot : detail::kCsrByName)
290	    detail::try_write_named(sess, reg_map, slot.first, state.*(slot.second));
291	
292	  for (uint16_t i = 0; i < HYBRID_PMP_CFG_NUM; ++i)
293	    detail::try_write_named(sess, reg_map, "pmpcfg" + std::to_string(i),
294	                            state.pmpcfg[i]);
295	  for (uint16_t i = 0; i < HYBRID_PMP_ADDR_NUM; ++i)
296	    detail::try_write_named(sess, reg_map, "pmpaddr" + std::to_string(i),
297	                            state.pmpaddr[i]);
298	
299	  if ((state.flags & HYBRID_FLAG_V) != 0u && state.vlenb > 0u
300	      && state.vlenb <= HYBRID_VLEN_BYTES_MAX) {
301	    detail::try_write_named(sess, reg_map, "vstart", state.vstart);
302	    const std::size_t vbytes = static_cast<std::size_t>(state.vlenb);
303	    for (uint16_t i = 0; i < 32; ++i) {
304	      const std::string name = "v" + std::to_string(i);
305	      detail::try_write_named_bytes(
306	        sess, reg_map, name,
307	        &state.vreg[static_cast<std::size_t>(i) * HYBRID_VLEN_BYTES_MAX],
308	        vbytes);
309	    }
310	  }
311	
312	  spdlog::info("hybrid handback: continuing target");
313	  sess.cont();
314	}
315	
316	// Top-level: spawns QEMU, restores state, waits for exit, returns exit
317	// status (or 128 + signal for abnormal termination).
318	inline auto run_qemu_handback(const std::string& qemu_binary,
319	                              const std::string& elf_path,
320	                              const hybrid_state_v1& state,
321	                              const std::string& shared_mem_path = {},
322	                              uint64_t shared_mem_size = 0) -> int
323	{
324	  const auto port = detail::pick_free_port();
325	  spdlog::info("hybrid handback: spawning {} -gdb tcp::{} -S",
326	               qemu_binary, port);
327	  const pid_t pid = detail::spawn_qemu(qemu_binary, elf_path, port,
328	                                       shared_mem_path, shared_mem_size);
329	
330	  try {
331	    restore_state_via_gdbstub(port, state, pid);
332	  } catch (const detail::ChildExitedDuringConnect& d) {
333	    return d.status;
334	  } catch (...) {
335	    ::kill(pid, SIGKILL);
336	    int wstat = 0;
337	    ::waitpid(pid, &wstat, 0);
338	    throw;
339	  }
340	
341	  int wstat = 0;
342	  if (::waitpid(pid, &wstat, 0) < 0)
343	    throw std::runtime_error(std::string{"waitpid: "}
344	                             + std::strerror(errno));
345	  if (WIFEXITED(wstat)) return WEXITSTATUS(wstat);
346	  if (WIFSIGNALED(wstat)) return 128 + WTERMSIG(wstat);
347	  return -1;
348	}
