202	TEST_CASE("resume polls DMSTATUS for halted before programming registers")
203	{
204	  RecordingBus bus;
205	  bus.dmstatus_value = (1u << 9) | (1u << 17);
206	
207	  hybrid::ResumeDriver driver(bus);
208	  driver.resume(rv64_state(0x80001000, 0));
209	
210	  // At least one DMSTATUS read happened, and it occurred before the first
211	  // DATA0/DATA1 write.
212	  std::optional<std::size_t> first_dmstatus_read;
213	  std::optional<std::size_t> first_data_write;
214	  for (std::size_t i = 0; i < bus.ops.size(); ++i) {
215	    const auto& op = bus.ops[i];
216	    if (op.kind == DmiOp::Kind::Read && op.reg == kDmstatus
217	        && !first_dmstatus_read)
218	      first_dmstatus_read = i;
219	    if (op.kind == DmiOp::Kind::Write && op.reg == kData0 && !first_data_write)
220	      first_data_write = i;
221	  }
222	  REQUIRE(first_dmstatus_read);
223	  REQUIRE(first_data_write);
224	  CHECK(*first_dmstatus_read < *first_data_write);
225	}
