250	namespace {
251	
252	auto cmd_regnos(const std::vector<DmiOp>& ops) -> std::vector<uint16_t>
253	{
254	  std::vector<uint16_t> ns;
255	  for (const auto& op : ops)
256	    if (op.kind == DmiOp::Kind::Write && op.reg == kCommand)
257	      ns.push_back(static_cast<uint16_t>(op.value & 0xffffu));
258	  return ns;
259	}
260	
261	auto contains_regno(const std::vector<uint16_t>& ns, uint16_t regno) -> bool
262	{
263	  for (auto n : ns) if (n == regno) return true;
264	  return false;
265	}
