275	  auto s = rv64_state(0x80001000, 0);
276	  s.flags  |= HYBRID_FLAG_FP | HYBRID_FLAG_V;
277	  s.mstatus = 0x1800ULL;
278	  for (int i = 0; i < 32; ++i) s.fpr[i] = 0xf0000000ULL + i;
279	  for (int i = 0; i < HYBRID_PMP_CFG_NUM; ++i)  s.pmpcfg[i]  = 0xa0 + i;
280	  for (int i = 0; i < HYBRID_PMP_ADDR_NUM; ++i) s.pmpaddr[i] = 0xb0 + i;
281	
282	  hybrid::ResumeDriver driver(bus);
283	  driver.resume(s);
