285	  const auto ns = cmd_regnos(bus.ops);
286	  for (uint16_t i = 0; i < 32; ++i)
287	    CHECK_FALSE(contains_regno(ns, hybrid::regno_fpr(i)));
288	  for (uint16_t csr : {0x300, 0x341, 0x305, 0x342, 0x343, 0x340,
289	                       0x302, 0x303, 0x344, 0x304, 0xb00, 0xb02, 0x180})
290	    CHECK_FALSE(contains_regno(ns, hybrid::regno_csr(csr)));
291	  for (uint16_t i = 0; i < HYBRID_PMP_CFG_NUM; ++i)
292	    CHECK_FALSE(contains_regno(ns, hybrid::regno_csr(0x3a0 + i)));
